"""HTTP-facing payment controller."""

from app.service import PaymentService as Service


class PaymentController:
    """Controller for payment requests."""

    def __init__(self, service: Service):
        self.service = service

    def create_payment(self, payment_id: str) -> str:
        return self.service.charge(payment_id)

"""Payment service and persistence boundary."""


class PaymentRepository:
    """Persist completed charges."""

    def save(self, payment_id: str) -> str:
        return payment_id


class PaymentService:
    """Coordinate payment operations."""

    def charge(self, payment_id: str) -> str:
        return self.repository.save(payment_id)

    def __init__(self, repository: PaymentRepository):
        self.repository = repository

def normalize_injected(value: str) -> str:
    cleaned = value.strip()
    lowered = cleaned.lower()
    return lowered.replace('-', '_')

